// 1. Sadə intersection type
interface Item {
  name: string;
  price: number;
}
interface Stock {
  inStock: boolean;
}
type Product = Item & Stock;
const product: Product = { name: "Shirt", price: 50, inStock: true };
// const invalidProduct: Product = { name: "Shirt", price: 50 }; // Xəta: inStock yoxdur

// 2. Type ilə intersection
type Id = { id: number };
type Details = { category: string };
type FullProduct = Id & Details & Item;
const fullProduct: FullProduct = { id: 1, category: "Clothing", name: "Jacket", price: 100 };

// 3. Funksiya ilə intersection type
function printProduct(product: Item & Stock): string {
  return `${product.name}: $${product.price}, Stock: ${product.inStock}`;
}

// 4. Intersection type ilə array
type Order = { orderId: number } & { items: Item[] };
const order: Order = { orderId: 101, items: [{ name: "Hat", price: 25 }] };

// 5. Intersection ilə opsiyonel xüsusiyyətlər
interface UserInfo {
  name: string;
}
interface Contact {
  email?: string;
}
type User = UserInfo & Contact;
const user: User = { name: "Alice" }; // email opsiyonel olduğu üçün tələb olunmur

